using testing::NiceMock;
using testing::Return;
using testing::ReturnRef;

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace CustomHeaderInjection {
namespace {

class CustomHeaderInjectionTest : public testing::Test {
public:
  const std::string request_config_yaml = R"EOF(
request_rules:
  - header_name: X-Custom-Header
    header_value: custom-value
  - header_name: X-Request-ID
    header_value: request-123
)EOF";

  const std::string response_config_yaml = R"EOF(
response_rules:
  - header_name: X-Response-Header
    header_value: response-value
)EOF";

  const std::string combined_config_yaml = R"EOF(
request_rules:
  - header_name: X-Custom-Header
    header_value: custom-value
response_rules:
  - header_name: X-Response-Header
    header_value: response-value
)EOF";

  void initializeFilter(const std::string& yaml) {
    envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection config;
    TestUtility::loadFromYaml(yaml, config);
    config_ = std::make_shared<Config>(config);
    filter_ = std::make_shared<CustomHeaderInjectionFilter>(config_);
    filter_->setDecoderFilterCallbacks(decoder_callbacks_);
    filter_->setEncoderFilterCallbacks(encoder_callbacks_);
  }

  ConfigSharedPtr config_;
  std::shared_ptr<CustomHeaderInjectionFilter> filter_;
  NiceMock<Http::MockStreamDecoderFilterCallbacks> decoder_callbacks_;
  NiceMock<Http::MockStreamEncoderFilterCallbacks> encoder_callbacks_;
};

/**
 * Test request header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicRequestHeaderInjection) {
  initializeFilter(request_config_yaml);
  Http::TestRequestHeaderMapImpl incoming_headers;

  EXPECT_EQ(Http::FilterHeadersStatus::Continue, filter_->decodeHeaders(incoming_headers, false));

  // Verify headers were injected
  EXPECT_EQ("custom-value", incoming_headers.get_("X-Custom-Header"));
  EXPECT_EQ("request-123", incoming_headers.get_("X-Request-ID"));

  filter_->onDestroy();
}

/**
 * Test response header injection.
 */
TEST_F(CustomHeaderInjectionTest, BasicResponseHeaderInjection) {
  initializeFilter(response_config_yaml);
  Http::TestResponseHeaderMapImpl response_headers;

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));

  // Verify headers were injected
  EXPECT_EQ("response-value", response_headers.get_("X-Response-Header"));

  filter_->onDestroy();
}

/**
 * Test both request and response header injection.
 */
TEST_F(CustomHeaderInjectionTest, CombinedHeaderInjection) {
  initializeFilter(combined_config_yaml);

  // Test request headers
  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));
  EXPECT_EQ("custom-value", request_headers.get_("X-Custom-Header"));

  // Test response headers
  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));
  EXPECT_EQ("response-value", response_headers.get_("X-Response-Header"));

  filter_->onDestroy();
}

/**
 * Test empty configuration.
 */
TEST_F(CustomHeaderInjectionTest, EmptyConfiguration) {
  initializeFilter("{}");

  Http::TestRequestHeaderMapImpl request_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(request_headers, false));

  Http::TestResponseHeaderMapImpl response_headers;
  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->encodeHeaders(response_headers, false));

  filter_->onDestroy();
}

/**
 * Test filter data and trailers pass through.
 */
TEST_F(CustomHeaderInjectionTest, DataAndTrailersPassThrough) {
  initializeFilter(request_config_yaml);

  Http::TestRequestHeaderMapImpl incoming_headers;
  filter_->decodeHeaders(incoming_headers, false);

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl trailers;
  EXPECT_EQ(Http::FilterTrailersStatus::Continue, filter_->decodeTrailers(trailers));

  filter_->onDestroy();
}

/**
 * Test per-route override.
 */
TEST_F(CustomHeaderInjectionTest, PerRouteOverride) {
  // Global config is empty.
  initializeFilter("{}");
  Http::TestRequestHeaderMapImpl incoming_headers;

  // Setup per route config.
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection
      config_proto;
  TestUtility::loadFromYaml(request_config_yaml, config_proto);
  Config per_route_config(config_proto, true);
  EXPECT_CALL(*decoder_callbacks_.route_, mostSpecificPerFilterConfig(_))
      .WillOnce(Return(&per_route_config));

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("custom-value", incoming_headers.get_("X-Custom-Header"));

  filter_->onDestroy();
}

} // namespace
} // namespace CustomHeaderInjection
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

syntax = "proto3";

package envoy.extensions.filters.http.custom_header_injection.v3;

import "udpa/annotations/status.proto";
import "validate/validate.proto";

option java_package = "io.envoyproxy.envoy.extensions.filters.http.custom_header_injection.v3";
option java_outer_classname = "CustomHeaderInjectionProto";
option java_multiple_files = true;
option go_package = "github.com/envoyproxy/go-control-plane/envoy/extensions/filters/http/custom_header_injection/v3;custom_header_injectionv3";
option (udpa.annotations.file_status).package_version_status = ACTIVE;

// [#protodoc-title: Custom Header Injection Filter]
//
// The configuration for injecting custom headers into requests and responses.
//
// Custom Header Injection :ref:`configuration overview <config_http_filters_custom_header_injection>`.
// [#extension: envoy.filters.http.custom_header_injection]

message CustomHeaderInjection {
  // Request header injection rules.
  repeated HeaderInjectionRule request_rules = 1;

  // Response header injection rules.
  repeated HeaderInjectionRule response_rules = 2;
}

message HeaderInjectionRule {
  // The name of the header to inject.
  string header_name = 1 [(validate.rules).string = {min_len: 1}];

  // The value of the header to inject.
  string header_value = 2;
}

