 */
TEST_F(CustomHeaderInjectionTest, DataAndTrailersPassThrough) {
  initializeFilter(request_config_yaml);

  Http::TestRequestHeaderMapImpl incoming_headers;
  filter_->decodeHeaders(incoming_headers, false);

  Buffer::OwnedImpl data("test data");
  EXPECT_EQ(Http::FilterDataStatus::Continue, filter_->decodeData(data, false));

  Http::TestRequestTrailerMapImpl trailers;
