/**
 * Test per-route override.
 */
TEST_F(CustomHeaderInjectionTest, PerRouteOverride) {
  // Global config is empty.
  initializeFilter("{}");
  Http::TestRequestHeaderMapImpl incoming_headers;

  // Setup per route config.
  envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection
      config_proto;
  TestUtility::loadFromYaml(request_config_yaml, config_proto);
  Config per_route_config(config_proto, true);
  EXPECT_CALL(*decoder_callbacks_.route_, mostSpecificPerFilterConfig(_))
      .WillOnce(Return(&per_route_config));

  EXPECT_EQ(Http::FilterHeadersStatus::Continue,
            filter_->decodeHeaders(incoming_headers, false));
  EXPECT_EQ("custom-value", incoming_headers.get_("X-Custom-Header"));

  filter_->onDestroy();
}

